import hashlib
import time

class TOTPAuthenticator:
    def __init__(self, secret):
        self.secret = secret
    
    def generate_totp(self):
        # Generate a TOTP code using the secret and current timestamp
        timestamp = int(time.time())
        hashed_timestamp = hashlib.sha1(str(timestamp).encode()).hexdigest()
        totp = int(hashed_timestamp, 16) % 10 ** 6
        return totp
    
    def validate_totp(self, code):
        # Validate the TOTP code by checking if it matches the expected value calculated from the secret and current timestamp
        expected_code = self.generate_totp()
        if code == expected_code:
            return True
        else:
            return False